# According to documentation. Other actions may be
# possible as well for list widgets.
actions = {
	0: "CLICK",
	1: "DCLICK",
	4: "COLLAPSE"
	}

def callback_list_widget(id_req, wdg, action):
	if action not in actions:
		print("Action:",action)
	else:
		print("Action:",actions[action])
	print("Now selected:")
	indices_selected = tde4.getListWidgetSelectedItems(id_req,wdg)
	for index in indices_selected:
		# For demo purposes we log the collapse/expanded state for nodes.
		if tde4.getListWidgetItemType(id_req,wdg,index) == "LIST_ITEM_NODE":
			col_exp_state = "collapsed" if tde4.getListWidgetItemCollapsedFlag(id_req,wdg,index) else "expanded"
		else:
			col_exp_state = "n/a"
		print("* index:",index,", userdata:", tde4.getListWidgetItemUserdata(id_req,wdg,index),", col/exp:",col_exp_state)

def insert_items_recursively(id_req, wdg_list, items, parent_index=-1):
	for item in items:
		# For demo purposes, we infer the item type from the presence of "children",
		# but in a real application you might want to include the type explicitly
		# in the data structure.
		item_type = "LIST_ITEM_NODE" if "children" in item else "LIST_ITEM_ATOM"
		index = tde4.insertListWidgetItem(id_req, wdg_list, item["label"], item["userdata"], item_type, parent_index)
		if "color" in item:
			tde4.setListWidgetItemColor(id_req, wdg_list,index,*item["color"])
		if "selectable" in item:
			tde4.setListWidgetItemSelectableFlag(id_req, wdg_list,index,int(item["selectable"]))
		if "children" in item and item["children"]:
			insert_items_recursively(id_req, wdg_list, item["children"], index)

def build_list_widget(id_req, name, tree_obj):
	# With multi-selection.
	tde4.addListWidget(id_req, name, name,1,300)
	insert_items_recursively(id_req, name, tree_obj)

# Build a tree-like data structure representing the items to be
# added to the list widget or parse from JSON or other source.
# Each item is a dict with "label", "userdata",
# and optionally "color", "selectable", and "children".
tree_obj = [
	{ "label": "item1", "color": [1.0,0.3,0.2], "userdata": 1, "children": [
			{ "label": "item1_1", "userdata": 11 },
			{ "label": "item1_2", "userdata": 12, "children": [
					{ "label": "item1_2_1", "userdata": 121 },
					{ "label": "item1_2_2", "userdata": 122 },
				]
			}
		]
	},
	{ "label": "item2", "color": [0.0,1.0,0.0], "userdata": 2, "children": [
			{ "label": "item2_1", "userdata": 21 }
		]
	},
	{ "label": "item3", "color": [0.4,0.6,1.0], "userdata": 3, "children": [
			{ "label": "item3_1", "userdata": 31 },
			{ "label": "item3_2", "userdata": 32 }
		]
	},
	{ "label": "item4-unselectable", "color": [1.0,1.0,0.5], "userdata": 4, "selectable": False, "children": [
			{ "label": "item4_1-unselectable", "userdata": 41, "selectable": False },
			{ "label": "item4_2", "userdata": 42 }
		]
	}
]

tde4.clearConsole()
id_req = tde4.createCustomRequester()
wdg = "My List"
build_list_widget(id_req, wdg, tree_obj)
tde4.setWidgetCallbackFunction(id_req,wdg,"callback_list_widget")

tde4.postCustomRequesterAndContinue(id_req,"My Requester",300,350)

