import tde4

def ensure_point_group():
    pg = tde4.getCurrentPGroup()
    if pg is None:
        print("No point group available; open a project before running this example.")
    return pg

def ensure_point(pg):
    if pg is None:
        return None
    pt = tde4.getFirstPoint(pg)
    if pt is None:
        pt = tde4.createPoint(pg)
        tde4.setPointName(pg, pt, "example_point")
    return pt

def ensure_camera():
    cam = tde4.getCurrentCamera()
    if cam is None:
        print("No camera available; choose or load a camera first.")
    return cam

def main():
    pgroup_id = ensure_point_group()
    if pgroup_id is None:
        return
    point_id = ensure_point(pgroup_id)
    if point_id is None:
        return
    camera_id = ensure_camera()
    if camera_id is None:
        return
    frame = tde4.getCurrentFrame(camera_id) or 1
    with_distortion = 1
    back_projection2_d = tde4.calcPointBackProjection2D(pgroup_id, point_id, camera_id, frame, with_distortion)
    print("calcPointBackProjection2D returned:", back_projection2_d)

if __name__ == "__main__":
    main()

