import tde4


def main():
    pgroup_id = tde4.getCurrentPGroup()
    if pgroup_id is None:
        pgroup_id = tde4.getFirstPGroup()
    if pgroup_id is None:
        raise RuntimeError("No point group available; create or load one first.")
    dconstr_ids = tde4.getDConstrList(pgroup_id, 0)
    if not dconstr_ids:
        if 'points' not in locals():
            points = tde4.getPointList(pgroup_id, 0)
        while len(points) < 2:
            points.append(tde4.createPoint(pgroup_id))
        dconstr_id = tde4.createDConstr(pgroup_id)
        tde4.setDConstrPoints(pgroup_id, dconstr_id, points[0], points[1])
        tde4.setDConstrDistance(pgroup_id, dconstr_id, 1.0)
    else:
        dconstr_id = dconstr_ids[0]
    distance = tde4.getDConstrDistance(pgroup_id, dconstr_id)
    print(f"distance = {distance}")


if __name__ == "__main__":
    main()

