import tde4


def ensure_point_group():
    pg = tde4.getCurrentPGroup()
    if pg is None:
        print("No point group available; open a project before running this example.")
    return pg


def ensure_point(pg):
    if pg is None:
        return None
    pt = tde4.getFirstPoint(pg)
    if pt is None:
        pt = tde4.createPoint(pg)
        tde4.setPointName(pg, pt, "example_point")
    return pt


def ensure_camera():
    cam = tde4.getCurrentCamera()
    if cam is None:
        print("No camera available; choose or load a camera first.")
    return cam


def ensure_point_pos_2d(pg, pt, cam, frame):
    # setPointTrackingBoxes2D has no effect for undefined 2D positions.
    if not tde4.isPointPos2DValid(pg, pt, cam, frame):
        tde4.setPointPosition2D(pg, pt, cam, frame, [0.5, 0.5])
        tde4.setPointStatus2D(pg, pt, cam, frame, "POINT_KEYFRAME")


def main():
    pgroup_id = ensure_point_group()
    if pgroup_id is None:
        return

    point_id = ensure_point(pgroup_id)
    if point_id is None:
        return

    camera_id = ensure_camera()
    if camera_id is None:
        return

    frame = 1
    ensure_point_pos_2d(pgroup_id, point_id, camera_id, frame)

    # Live-tested setup: large search area, smaller pattern, centered point.
    search = [0.2, 0.2]
    pattern = [0.1, 0.1]
    offset = [0.05, 0.05]
    rot = 0.0

    tde4.setPointTrackingBoxes2D(
        pgroup_id, point_id, camera_id, frame, search, pattern, offset, rot
    )

    print(
        "setPointTrackingBoxes2D executed with "
        "search=[0.2,0.2], pattern=[0.1,0.1], offset=[0.05,0.05], rot=0.0 at frame 1"
    )


if __name__ == "__main__":
    main()

